use cardano/assets
use cardano/transaction.{InlineDatum, OutputReference, Transaction}
use aiken/collection/list

pub type EscrowDatum {
  owner: ByteArray,
  amount: Int,
}

validator escrow_inline {
  spend(
    datum: Option<EscrowDatum>,
    redeemer: Data,
    own_ref: OutputReference,
    self: Transaction,
  ) {
    let matching_output =
      list.find(
        self.outputs,
        fn(output) { output.address == (
          list.find(
            self.inputs,
            fn(input) { input.output_reference == own_ref }
          ) |> fn(opt) {
            when opt is {
              Some(inp) -> inp.output.address
              None -> fail
            }
          }
        ) }
      )
    when matching_output is {
      Some(output) -> {
        expect InlineDatum(raw) = output.datum
        expect typed: EscrowDatum = raw
        typed.amount > 0
      }
      None ->
        when datum is {
          Some(d) -> d.amount > 0
          None -> False
        }
    }
  }
}

use aiken/collection/list
use cardano/governance.{GovernanceActionId, Voter}
use cardano/transaction.{Transaction}

const authorized_key: ByteArray =
  #"deadbeefdeadbeefdeadbeefdeadbeefdeadbeefdeadbeefdeadbeefdeadbeef"

validator governance_vote {
  vote(
    _redeemer: Data,
    _voter: Voter,
    _proposal: GovernanceActionId,
    self: Transaction,
  ) {
    list.has(self.extra_signatories, authorized_key)
  }
}

